// Required: prevents Next.js 308 trailing-slash redirect on /ingest/ paths
// which fires before rewrites and breaks the PostHog proxy (no CORS on 308)
skipTrailingSlashRedirect: true,
async rewrites() {
  // Order matters: static assets must match before the catch-all
  return [
    {
      source: "/ingest/static/:path*",
      destination: "https://us-assets.i.posthog.com/static/:path*",
    },
    {
      source: "/ingest/:path*",
      destination: "https://us.i.posthog.com/:path*",
    },
  ];
},

